<?php

if ( ! defined( 'ABSPATH' ) ) {
	exit;
}

/**
 * Helper class for product card data extraction and rendering.
 */
class HPCO_Helpers {

	/**
	 * Get Secure Custom Fields (SCF) or ACF specification fields for a product.
	 *
	 * @param int $product_id Product ID.
	 * @return array Specs data.
	 */
	public static function get_product_specs( $product_id ) {
		if ( ! function_exists( 'get_field' ) ) {
			return array();
		}

		$specs  = array();
		$fields = array(
			'floors'    => array(
				'label'           => __( 'Floors', 'house-product-card-override' ),
				'icon_id'         => 'hpc-icon-floors',
				'suffix_singular' => ' Floor',
				'suffix_plural'   => ' Floors',
			),
			'bedrooms'  => array(
				'label'           => __( 'Bedrooms', 'house-product-card-override' ),
				'icon_id'         => 'hpc-icon-bedrooms',
				'suffix_singular' => ' Bedroom',
				'suffix_plural'   => ' Bedrooms',
			),
			'bathrooms' => array(
				'label'           => __( 'Bathrooms', 'house-product-card-override' ),
				'icon_id'         => 'hpc-icon-bathrooms',
				'suffix_singular' => ' Bathroom',
				'suffix_plural'   => ' Bathrooms',
			),
			'width'     => array(
				'label'   => __( 'Width', 'house-product-card-override' ),
				'icon_id' => 'hpc-icon-width',
				'prefix'  => 'Width: ',
				'suffix'  => 'm',
			),
			'length'    => array(
				'label'   => __( 'Length', 'house-product-card-override' ),
				'icon_id' => 'hpc-icon-length',
				'prefix'  => 'Length: ',
				'suffix'  => 'm',
			),
			'area'      => array(
				'label'   => __( 'Area', 'house-product-card-override' ),
				'icon_id' => 'hpc-icon-area',
				'prefix'  => 'Area: ',
				'suffix'  => ' m<sup>2</sup>',
			),
		);

		/**
		 * Loop through the fields and add them to the specs array.
		 */
		foreach ( $fields as $key => $config ) {
			$value = get_field( $key, $product_id );
			if ( $value !== null && $value !== '' && $value !== false ) {
				$prefix = $config['prefix'] ?? '';
				$suffix = $config['suffix'] ?? '';
				
				if ( isset( $config['suffix_singular'], $config['suffix_plural'] ) ) {
					$numeric_value = floatval( $value );
					$suffix        = ( $numeric_value > 1 ) ? $config['suffix_plural'] : $config['suffix_singular'];
				}

				$specs[] = array(
					'label'   => $config['label'],
					'icon_id' => $config['icon_id'],
					'value'   => $prefix . sanitize_text_field( $value ) . $suffix,
				);
			}
		}

		return $specs;
	}

	/**
	 * Render rating stars.
	 *
	 * @param float $rating     The average rating.
	 * @param int   $product_id Product ID for unique gradient ID.
	 * @return string Star SVGs.
	 */
	public static function render_stars( $rating, $product_id = 0 ) {
		$rating   = max( 0, min( 5, (float) $rating ) );
		$html     = '';
		$full     = (int) floor( $rating );
		$has_half = ( $rating - $full ) >= 0.5;
		$empty    = 5 - $full - ( $has_half ? 1 : 0 );

		$grad_id = 'hpco-half-' . (int) $product_id;

		for ( $i = 0; $i < $full; $i++ ) {
			$html .= '<svg class="hpc-star hpc-star--full" width="14" height="14" aria-hidden="true"><use href="#hpc-star-full"></use></svg>';
		}
		
		if ( $has_half ) {
			$html .= '<svg class="hpc-star hpc-star--half" width="14" height="14" aria-hidden="true"><defs><linearGradient id="' . esc_attr( $grad_id ) . '"><stop offset="50%" stop-color="currentColor"/><stop offset="50%" stop-color="transparent"/></linearGradient></defs><use href="#hpc-star-full" fill="url(#' . esc_attr( $grad_id ) . ')" stroke="currentColor" stroke-width="1"></use></svg>';
		}
		
		for ( $i = 0; $i < $empty; $i++ ) {
			$html .= '<svg class="hpc-star hpc-star--empty" width="14" height="14" aria-hidden="true"><use href="#hpc-star-empty"></use></svg>';
		}


		return $html;
	}

